    """Strip whitespace from all string values."""
    return {k: v.strip() for k, v in d.items()}

def count_values(d):
    """Count characters in each string value."""
    return {k: len(v) for k, v in d.items()}

def invert_dict(d):
    """Invert keys and values."""
    return {v: k for k, v in d.items()}

